    knowledgebaseTitle:decision.knowledgebaseTitle,
    knowledgebaseLatest:decision.knowledgebaseLatest,
    criteriaCount:decision.criteriaCount,
    applicationValidity:{result:nice(decision.lodgementPosition),legalStatus:decision.legalStatus,blockers:(decision.blockers||[]).map(f=>f.criterion)},
    criterionFindings:(decision.findings||[]).map(f=>({criterion:f.criterion,status:f.status,finding:f.finding,evidenceConsidered:(f.evidenceConsidered||[]).join('; '),legalConsequence:f.legalConsequence,evidenceGap:f.evidenceGap,recommendation:f.recommendation,legalEffect:f.legalEffect,severity:f.severity,source:f.source})),
    evidenceRequired:decision.evidenceRequired||[],
